    this.renderInfoCard(cards, "shield-alert", this.t("\u6392\u67E5_\u7ED3\u8BBA_\u6807\u9898"), this.t("\u6392\u67E5_\u7ED3\u8BBA_\u6587\u672C"));
    this.renderInfoCard(cards, "scan-search", this.t("\u6392\u67E5_\u8986\u76D6_\u6807\u9898"), this.t("\u6392\u67E5_\u8986\u76D6_\u6587\u672C"));
