  \u6392\u67E5_Tab_\u6807\u9898: "\u041F\u043E\u0438\u0441\u043A \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u043E\u0432 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432",
  \u6392\u67E5_Tab_\u8BF4\u660E: "\u0412\u0438\u0437\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043D\u0430\u0431\u043E\u0440\u0430\u043C\u0438 \u0432\u043A\u043B\u044E\u0447\u0435\u043D\u043D\u044B\u0445 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432, \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u0439 \u0441\u0432\u044F\u0437\u044C\u044E, \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438 \u0438 \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435\u043C.",
  \u6392\u67E5_\u7ED3\u8BBA_\u6807\u9898: "\u0413\u0430\u0440\u0430\u043D\u0442\u0438\u044F \u043D\u0435 100%",
  \u6392\u67E5_\u7ED3\u8BBA_\u6587\u672C: "\u041F\u0440\u043E\u0446\u0435\u0441\u0441 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u0432\u0430\u0448\u0435\u0439 \u043E\u0446\u0435\u043D\u043A\u0438 \u0432\u043E\u0441\u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B. \u041D\u0435\u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B, \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u043E\u0442 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043A, \u043F\u043E\u0440\u044F\u0434\u043E\u043A \u0437\u0430\u0433\u0440\u0443\u0437\u043A\u0438 \u0438\u043B\u0438 \u0446\u0435\u043F\u043E\u0447\u043A\u0438 \u0438\u0437 3+ \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u043C\u043E\u0436\u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u0443\u0437\u0438\u0442\u044C, \u043D\u043E \u043D\u0435 \u0433\u0430\u0440\u0430\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0442\u043E\u0447\u043D\u043E.",
  \u6392\u67E5_\u8986\u76D6_\u6807\u9898: "\u041F\u043E\u043A\u0440\u044B\u0432\u0430\u0435\u043C\u044B\u0435 \u0441\u043B\u0443\u0447\u0430\u0438",
  \u6392\u67E5_\u8986\u76D6_\u6587\u672C: "\u041F\u043E\u043C\u043E\u0433\u0430\u0435\u0442 \u043D\u0430\u0439\u0442\u0438 \u043E\u0434\u0438\u043D \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u043D\u044B\u0439 \u043F\u043B\u0430\u0433\u0438\u043D, \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442 \u0434\u0432\u0443\u0445 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u0438 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u043D\u044B\u0435 \u043F\u0430\u0440\u044B \u043C\u0435\u0436\u0434\u0443 \u0440\u0430\u0437\u0434\u0435\u043B\u0430\u043C\u0438 \u043F\u043E\u0441\u043B\u0435 \u0431\u0438\u043D\u0430\u0440\u043D\u043E\u0433\u043E \u043F\u043E\u0438\u0441\u043A\u0430.",
  \u6392\u67E5_\u9650\u5236_\u6807\u9898: "\u0422\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F \u0440\u0443\u0447\u043D\u043E\u0435 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435",
  \u6392\u67E5_\u9650\u5236_\u6587\u672C: "\u041F\u043E\u0441\u043B\u0435 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u044F \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u043F\u043E\u0432\u0442\u043E\u0440\u0438\u0442\u0435 \u0442\u0435\u0441\u0442 \u0438 \u0434\u0430\u0439\u0442\u0435 \u043E\u0442\u0432\u0435\u0442. \u0415\u0441\u043B\u0438 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043F\u0435\u0440\u0435\u0437\u0430\u043F\u0443\u0441\u043A\u0430, \u043E\u0436\u0438\u0434\u0430\u043D\u0438\u044F, \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0433\u043E \u0444\u0430\u0439\u043B\u0430 \u0438\u043B\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0439\u0442\u0435 \u043E\u0434\u0438\u043D\u0430\u043A\u043E\u0432\u044B\u0435 \u0443\u0441\u043B\u043E\u0432\u0438\u044F \u0442\u0435\u0441\u0442\u0430 \u043D\u0430 \u043A\u0430\u0436\u0434\u043E\u043C \u0448\u0430\u0433\u0435.",
