  \u5B89\u88C5_\u4E3B\u9898\u9519\u8BEF_\u901A\u7528: "\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C \u0442\u0435\u043C\u0443. \u041F\u0440\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u0440\u0435\u043F\u043E\u0437\u0438\u0442\u043E\u0440\u0438\u0439, \u0432\u0435\u0440\u0441\u0438\u044E \u0438\u043B\u0438 \u0441\u0435\u0442\u044C.",
