  \u6765\u6E90_\u68C0\u67E5\u66F4\u65B0_\u6309\u94AE: "\u041F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C \u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435",
  \u6765\u6E90_\u66F4\u65B0_\u6309\u94AE: "\u041E\u0431\u043D\u043E\u0432\u0438\u0442\u044C",
  \u6765\u6E90_\u91CD\u88C5_\u6309\u94AE: "\u041F\u0435\u0440\u0435\u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C",
  \u6765\u6E90_\u6253\u5F00GitHub_\u6309\u94AE: "\u041E\u0442\u043A\u0440\u044B\u0442\u044C GitHub",
  \u6765\u6E90_\u505C\u6B62\u8DDF\u8E2A_\u6309\u94AE: "\u041E\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435",
  \u6765\u6E90_\u505C\u6B62\u8DDF\u8E2A_\u786E\u8BA4: "\u041E\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430? \u041F\u043B\u0430\u0433\u0438\u043D \u0438\u043B\u0438 \u0442\u0435\u043C\u0430 \u043D\u0435 \u0431\u0443\u0434\u0443\u0442 \u0443\u0434\u0430\u043B\u0435\u043D\u044B.",
  \u6765\u6E90_\u9875\u9762_\u6807\u9898: "\u0423\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0430 \u0438 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0438",
  \u6765\u6E90_\u9875\u9762_\u63CF\u8FF0: "\u0423\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0439\u0442\u0435 \u043F\u043B\u0430\u0433\u0438\u043D\u044B \u0438\u043B\u0438 \u0442\u0435\u043C\u044B \u0441 GitHub \u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0439\u0442\u0435 \u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0430\u043C\u0438 \u043D\u0430 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0438 \u0434\u043B\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0445 \u043F\u0440\u043E\u0432\u0435\u0440\u043E\u043A, \u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0439 \u0438 \u043F\u0435\u0440\u0435\u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043E\u043A.",
  \u6765\u6E90_\u8DDF\u8E2A\u6765\u6E90_\u6807\u9898: "\u041E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u0442\u044C \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A",
  \u6765\u6E90_\u8DDF\u8E2A\u6765\u6E90_\u63CF\u8FF0: "\u041F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u0442\u044C \u044D\u0442\u043E\u0442 \u0440\u0435\u043F\u043E\u0437\u0438\u0442\u043E\u0440\u0438\u0439 GitHub \u043F\u043E\u0441\u043B\u0435 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 \u0434\u043B\u044F \u0431\u0443\u0434\u0443\u0449\u0438\u0445 \u043F\u0440\u043E\u0432\u0435\u0440\u043E\u043A, \u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0439 \u0438 \u043F\u0435\u0440\u0435\u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043E\u043A.",
  \u8BBE\u7F6E_\u6807\u7B7E\u8BBE\u7F6E_\u6807\u9898: "\u041C\u0435\u043D\u0435\u0434\u0436\u0435\u0440 \u0442\u0435\u0433\u043E\u0432",
  \u8BBE\u7F6E_\u6807\u7B7E\u8BBE\u7F6E_\u63CF\u8FF0: "\u0423\u043F\u0440\u0430\u0432\u043B\u044F\u0439\u0442\u0435 \u0442\u0435\u0433\u0430\u043C\u0438, \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B\u043C\u0438 \u0432 \u0440\u0435\u0436\u0438\u043C\u0435 \u0440\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432.",
  \u8BBE\u7F6E_\u6807\u7B7E\u8BBE\u7F6E_\u65B0\u589E\u6807\u7B7E: "\u0414\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u0442\u0435\u0433",
  \u8BBE\u7F6E_\u6807\u7B7E\u8BBE\u7F6E_\u7CFB\u7EDF\u6807\u7B7E\u4E0D\u53EF\u5220\u9664: "\u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0435 \u0442\u0435\u0433\u0438 \u043D\u0435\u043B\u044C\u0437\u044F \u0443\u0434\u0430\u043B\u0438\u0442\u044C",
  \u8BBE\u7F6E_\u6807\u7B7E\u8BBE\u7F6E_\u5220\u9664\u6807\u7B7E: "\u0423\u0434\u0430\u043B\u0438\u0442\u044C \u0442\u0435\u0433",
  \u8BBE\u7F6E_\u5206\u7EC4\u8BBE\u7F6E_\u6807\u9898: "\u041C\u0435\u043D\u0435\u0434\u0436\u0435\u0440 \u0433\u0440\u0443\u043F\u043F",
  \u8BBE\u7F6E_\u5206\u7EC4\u8BBE\u7F6E_\u63CF\u8FF0: "\u0423\u043F\u0440\u0430\u0432\u043B\u044F\u0439\u0442\u0435 \u0433\u0440\u0443\u043F\u043F\u0430\u043C\u0438, \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B\u043C\u0438 \u0432 \u0440\u0435\u0436\u0438\u043C\u0435 \u0440\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432.",
  \u8BBE\u7F6E_\u5206\u7EC4\u8BBE\u7F6E_\u65B0\u589E\u5206\u7EC4: "\u0414\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u0433\u0440\u0443\u043F\u043F\u0443",
  \u8BBE\u7F6E_\u5206\u7EC4\u8BBE\u7F6E_\u5220\u9664\u5206\u7EC4: "\u0423\u0434\u0430\u043B\u0438\u0442\u044C \u0433\u0440\u0443\u043F\u043F\u0443",
  \u8BBE\u7F6E_\u5206\u7C7B_\u65B0\u589E\u63CF\u8FF0: "\u0412\u0432\u0435\u0434\u0438\u0442\u0435 \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0439 ID, \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0430\u0435\u043C\u043E\u0435 \u0438\u043C\u044F \u0438 \u0446\u0432\u0435\u0442.",
