  \u8BBE\u7F6E_\u5206\u7C7B_\u4ECD\u6709\u63D2\u4EF6\u4F7F\u7528\u4E0D\u53EF\u5220\u9664: "\u0412\u0441\u0435 \u0435\u0449\u0435 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u043F\u043B\u0430\u0433\u0438\u043D\u0430\u043C\u0438 \u0438 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0443\u0434\u0430\u043B\u0435\u043D\u043E",
  \u8BBE\u7F6E_\u5206\u7C7B_ID\u8BF4\u660E: "ID \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0441\u043E\u043F\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F. \u041D\u0435 \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u043C\u0435\u043D\u044F\u0442\u044C \u0435\u0433\u043E \u043F\u043E\u0441\u043B\u0435 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F.",
  \u5206\u7EC4\u7F16\u8F91_\u6807\u9898: "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0433\u0440\u0443\u043F\u043F\u0443",
  \u5206\u7EC4\u7F16\u8F91_\u8BF4\u660E: "\u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0433\u0440\u0443\u043F\u043F\u0443 \u0434\u043B\u044F \u0442\u0435\u043A\u0443\u0449\u0435\u0433\u043E \u043F\u043B\u0430\u0433\u0438\u043D\u0430 \u0438\u043B\u0438 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u0442\u0435 \u0438\u043C\u0435\u043D\u0430 \u0438 \u0446\u0432\u0435\u0442\u0430 \u0433\u0440\u0443\u043F\u043F \u043D\u0430\u043F\u0440\u044F\u043C\u0443\u044E.",
  \u5206\u7EC4\u7F16\u8F91_\u9009\u62E9\u6807\u9898: "\u0412\u044B\u0431\u043E\u0440 \u0433\u0440\u0443\u043F\u043F\u044B",
  \u5206\u7EC4\u7F16\u8F91_\u9009\u62E9\u8BF4\u660E: "{id} \xB7 \u0432\u044B\u0431\u0440\u0430\u043D\u043E \u0433\u0440\u0443\u043F\u043F: {selected}/{total}",
  \u5206\u7EC4\u7F16\u8F91_\u5206\u7EC4\u540D\u79F0_\u6807\u7B7E: "\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u0433\u0440\u0443\u043F\u043F\u044B",
  \u5206\u7EC4\u7F16\u8F91_\u521B\u5EFA\u5206\u7EC4: "\u0421\u043E\u0437\u0434\u0430\u0442\u044C \u0433\u0440\u0443\u043F\u043F\u0443",
  \u5206\u7EC4\u7F16\u8F91_\u521B\u5EFA\u5168\u5C40\u5206\u7EC4: "\u0421\u043E\u0437\u0434\u0430\u0442\u044C \u043D\u043E\u0432\u0443\u044E \u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u0443\u044E \u0433\u0440\u0443\u043F\u043F\u0443.",
  \u6807\u7B7E\u7F16\u8F91_\u6807\u9898: "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0442\u0435\u0433\u0438",
  \u6807\u7B7E\u7F16\u8F91_\u8BF4\u660E: "\u041D\u0430\u0437\u043D\u0430\u0447\u044C\u0442\u0435 \u0442\u0435\u0433\u0438 \u0442\u0435\u043A\u0443\u0449\u0435\u043C\u0443 \u043F\u043B\u0430\u0433\u0438\u043D\u0443 \u0438\u043B\u0438 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u0442\u0435 \u0438\u043C\u0435\u043D\u0430 \u0438 \u0446\u0432\u0435\u0442\u0430 \u0442\u0435\u0433\u043E\u0432 \u043D\u0430\u043F\u0440\u044F\u043C\u0443\u044E.",
  \u6807\u7B7E\u7F16\u8F91_\u5206\u914D\u6807\u9898: "\u041D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0442\u0435\u0433\u043E\u0432",
  \u6807\u7B7E\u7F16\u8F91_\u5206\u914D\u8BF4\u660E: "{id} \xB7 \u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u043E \u0442\u0435\u0433\u043E\u0432: {selected}/{total}",
  \u6807\u7B7E\u7F16\u8F91_\u81EA\u52A8\u7BA1\u7406\u6807\u7B7E\u4E0D\u53EF\u624B\u52A8\u5207\u6362: "\u0410\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u044B\u0439 \u0442\u0435\u0433 \u043D\u0435\u043B\u044C\u0437\u044F \u043F\u0435\u0440\u0435\u043A\u043B\u044E\u0447\u0430\u0442\u044C \u0432\u0440\u0443\u0447\u043D\u0443\u044E",
  \u6807\u7B7E\u7F16\u8F91_\u6807\u7B7E\u540D\u79F0_\u6807\u7B7E: "\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u0442\u0435\u0433\u0430",
  \u6807\u7B7E\u7F16\u8F91_\u521B\u5EFA\u6807\u7B7E: "\u0421\u043E\u0437\u0434\u0430\u0442\u044C \u0442\u0435\u0433",
  \u6807\u7B7E\u7F16\u8F91_\u521B\u5EFA\u5168\u5C40\u6807\u7B7E: "\u0421\u043E\u0437\u0434\u0430\u0442\u044C \u043D\u043E\u0432\u044B\u0439 \u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u044B\u0439 \u0442\u0435\u0433.",
  Ribbon_\u5DF2\u9690\u85CF_\u901A\u77E5: "\u0421\u043A\u0440\u044B\u0442\u0430 \u0438\u043A\u043E\u043D\u043A\u0430 Ribbon: {name}",
  Ribbon_\u529F\u80FD\u7F16\u6392_\u6807\u9898: "\u041A\u043E\u043C\u043F\u043E\u043D\u043E\u0432\u043A\u0430 Ribbon",
  Ribbon_\u529F\u80FD\u7F16\u6392_\u8BF4\u660E: "\u0418\u0437\u043C\u0435\u043D\u044F\u0439\u0442\u0435 \u043F\u043E\u0440\u044F\u0434\u043E\u043A \u0438\u043A\u043E\u043D\u043E\u043A Ribbon \u0438 \u0438\u0445 \u0432\u0438\u0434\u0438\u043C\u043E\u0441\u0442\u044C. \u0421\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0434\u0430\u043D\u043D\u044B\u0445 BPM, \u043D\u0435 \u0432 \u043A\u043E\u043D\u0444\u0438\u0433\u0443\u0440\u0430\u0446\u0438\u0438 \u0440\u0430\u0431\u043E\u0447\u0435\u0439 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 Obsidian.",
  Ribbon_\u91CD\u7F6E_\u63D0\u793A: "\u041F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u0432\u0441\u0435 \u0438 \u043E\u0442\u0441\u043E\u0440\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043F\u043E \u0438\u043C\u0435\u043D\u0438",
  Ribbon_\u91CD\u7F6E_\u786E\u8BA4: "\u0421\u0431\u0440\u043E\u0441\u0438\u0442\u044C \u043A\u043E\u043C\u043F\u043E\u043D\u043E\u0432\u043A\u0443 Ribbon? \u0411\u0443\u0434\u0443\u0442 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u044B \u0432\u0441\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B Ribbon \u0438 \u043E\u0442\u0441\u043E\u0440\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u044B \u043F\u043E \u0438\u043C\u0435\u043D\u0438.",
  \u5206\u4EAB_\u5171\u4EAB\u63D2\u4EF6_\u6807\u9898: "\u041F\u043E\u0434\u0435\u043B\u0438\u0442\u044C\u0441\u044F \u043F\u043B\u0430\u0433\u0438\u043D\u0430\u043C\u0438",
  \u5206\u4EAB_\u5206\u4EAB\u94FE\u63A5_\u6807\u9898: "\u0421\u0441\u044B\u043B\u043A\u0430 \u0434\u043B\u044F \u043E\u0431\u043C\u0435\u043D\u0430",
  \u5206\u4EAB_\u8BF7\u8F93\u5165\u5206\u4EAB\u94FE\u63A5: "\u0412\u0432\u0435\u0434\u0438\u0442\u0435 \u0441\u0441\u044B\u043B\u043A\u0443 \u0434\u043B\u044F \u043E\u0431\u043C\u0435\u043D\u0430",
  \u5206\u4EAB_\u5BFC\u5165_\u6309\u94AE: "\u0418\u043C\u043F\u043E\u0440\u0442",
  \u5206\u4EAB_\u5BFC\u51FA_\u6309\u94AE: "\u042D\u043A\u0441\u043F\u043E\u0440\u0442",
  \u5206\u4EAB_\u5BFC\u5165\u63D2\u4EF6_\u63D0\u793A: "\u0418\u043C\u043F\u043E\u0440\u0442 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432",
  \u5206\u4EAB_\u5BFC\u51FA\u63D2\u4EF6_\u63D0\u793A: "\u042D\u043A\u0441\u043F\u043E\u0440\u0442 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432",
  \u5206\u4EAB_\u4E0B\u8F7D\u63D2\u4EF6_\u63D0\u793A: "\u0421\u043A\u0430\u0447\u0430\u0442\u044C \u043F\u043B\u0430\u0433\u0438\u043D",
