  \u5BFC\u5165\u5BFC\u51FA_\u9009\u9879_\u4E3B\u9898: "\u041A\u0430\u0442\u0430\u043B\u043E\u0433 \u0442\u0435\u043C",
  \u5BFC\u5165\u5BFC\u51FA_\u9009\u9879_\u4E3B\u9898\u8BF4\u660E: "\u042D\u043A\u0441\u043F\u043E\u0440\u0442 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u0442\u0435\u043C \u0438 \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u0435\u043C\u044B\u0445 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u0432 \u0442\u0435\u043C.",
  \u5BFC\u5165\u5BFC\u51FA_\u9009\u9879_\u5206\u7C7B: "\u0422\u0430\u043A\u0441\u043E\u043D\u043E\u043C\u0438\u044F",
