  \u5BFC\u5165\u5BFC\u51FA_\u751F\u6210\u4E2D: "\u0421\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u043F\u0430\u043A\u0435\u0442\u0430 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432",
  \u5BFC\u5165\u5BFC\u51FA_\u751F\u6210\u51C6\u5907: "\u0421\u0431\u043E\u0440 \u0441\u043F\u0438\u0441\u043A\u043E\u0432 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u0438 \u0442\u0435\u043C Obsidian",
  \u5BFC\u5165\u5BFC\u51FA_\u5DF2\u4E0B\u8F7D: "\u041F\u0430\u043A\u0435\u0442 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u0441\u043E\u0437\u0434\u0430\u043D: {name}",
  \u5BFC\u5165\u5BFC\u51FA_\u5DF2\u4FDD\u5B58: "\u041F\u0430\u043A\u0435\u0442 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D: {path}",
