  \u5BFC\u5165\u5BFC\u51FA_\u9009\u62E9\u6587\u4EF6\u8BF4\u660E: "\u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0438\u043B\u0438 \u043F\u0435\u0440\u0435\u0442\u0430\u0449\u0438\u0442\u0435 JSON-\u043F\u0430\u043A\u0435\u0442 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 Obsidian.",
  \u5BFC\u5165\u5BFC\u51FA_\u6587\u4EF6\u65E0\u6548: "\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u043F\u0430\u043A\u0435\u0442 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432. \u0424\u043E\u0440\u043C\u0430\u0442 \u043D\u0435 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F.",
  \u5BFC\u5165\u5BFC\u51FA_\u5BFC\u51FA\u5217\u8868: "\u0421\u043F\u0438\u0441\u043E\u043A \u044D\u043A\u0441\u043F\u043E\u0440\u0442\u0430",
