  \u5BFC\u5165\u5BFC\u51FA_\u63D2\u4EF6\u4E0B\u8F7D\u5217\u8868: "\u0417\u0430\u0433\u0440\u0443\u0437\u043A\u0438 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432",
  \u5BFC\u5165\u5BFC\u51FA_\u4E3B\u9898\u4E0B\u8F7D\u5217\u8868: "\u0417\u0430\u0433\u0440\u0443\u0437\u043A\u0438 \u0442\u0435\u043C",
  \u5BFC\u5165\u5BFC\u51FA_\u4E0B\u8F7D\u6E05\u5355\u6807\u9898: "\u0421\u043F\u0438\u0441\u043E\u043A \u0437\u0430\u0433\u0440\u0443\u0437\u043E\u043A",
  \u5BFC\u5165\u5BFC\u51FA_\u4E0B\u8F7D\u6E05\u5355\u8BF4\u660E: "\u041F\u043E\u0441\u043B\u0435 \u0437\u0430\u0433\u0440\u0443\u0437\u043A\u0438 \u043F\u0430\u043A\u0435\u0442\u0430 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u0441\u043A\u0430\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B \u0437\u0434\u0435\u0441\u044C \u0438\u043B\u0438 \u0441\u043A\u0430\u0447\u0430\u0439\u0442\u0435 \u0432\u0441\u0435 \u0441\u0440\u0430\u0437\u0443.",
  \u5BFC\u5165\u5BFC\u51FA_\u672A\u8F7D\u5165\u63D2\u4EF6\u5305: "\u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u043F\u0430\u043A\u0435\u0442 \u043F\u043B\u0430\u0433\u0438\u043D\u043E\u0432 \u0432\u044B\u0448\u0435, \u0447\u0442\u043E\u0431\u044B \u0441\u043F\u0440\u0430\u0432\u0430 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B\u0435 \u0434\u043B\u044F \u0437\u0430\u0433\u0440\u0443\u0437\u043A\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B.",
  \u5BFC\u5165\u5BFC\u51FA_\u4E0B\u8F7D\u6309\u94AE: "\u0421\u043A\u0430\u0447\u0430\u0442\u044C",
