  \u6392\u67E5_Tab_\u8BF4\u660E: "\uD65C\uC131\uD654 \uC9D1\uD569, \uC0AC\uC6A9\uC790 \uD53C\uB4DC\uBC31, \uACB0\uACFC, \uBCF5\uC6D0 \uC791\uC5C5\uC744 \uC2DC\uAC01\uC801 \uC6CC\uD06C\uD50C\uB85C\uB85C \uAD00\uB9AC\uD569\uB2C8\uB2E4.",
  \u6392\u67E5_\u7ED3\u8BBA_\u6807\u9898: "100% \uBCF4\uC7A5\uD560 \uC218 \uC5C6\uC74C",
  \u6392\u67E5_\u7ED3\u8BBA_\u6587\u672C: "\uC774 \uACFC\uC815\uC740 \uBB38\uC81C\uAC00 \uC7AC\uD604\uB418\uB294\uC9C0\uC5D0 \uB300\uD55C \uC0AC\uC6A9\uC790\uC758 \uD310\uB2E8\uC5D0 \uC758\uC874\uD569\uB2C8\uB2E4. \uAC04\uD5D0\uC801 \uBB38\uC81C, \uC124\uC815 \uC758\uC874 \uB3D9\uC791, \uB85C\uB4DC \uC21C\uC11C, 3\uAC1C \uC774\uC0C1 \uD50C\uB7EC\uADF8\uC778 \uC5F0\uC1C4 \uCDA9\uB3CC\uC740 \uBC94\uC704\uB97C \uC881\uD790 \uC218 \uC788\uC744 \uBFD0 \uC808\uB300 \uBCF4\uC7A5\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.",
  \u6392\u67E5_\u8986\u76D6_\u6807\u9898: "\uB300\uC0C1 \uC0AC\uB840",
  \u6392\u67E5_\u8986\u76D6_\u6587\u672C: "\uB2E8\uC77C \uBB38\uC81C \uD50C\uB7EC\uADF8\uC778, \uB450 \uD50C\uB7EC\uADF8\uC778 \uCDA9\uB3CC, \uC774\uBD84 \uD0D0\uC0C9 \uD6C4 \uD30C\uD2F0\uC158\uC744 \uAC00\uB85C\uC9C0\uB974\uB294 \uCDA9\uB3CC \uC30D\uC744 \uCC3E\uB294 \uB370 \uB3C4\uC6C0\uC744 \uC90D\uB2C8\uB2E4.",
  \u6392\u67E5_\u9650\u5236_\u6807\u9898: "\uC218\uB3D9 \uD655\uC778 \uD544\uC694",
  \u6392\u67E5_\u9650\u5236_\u6587\u672C: "\uAC01 \uD50C\uB7EC\uADF8\uC778 \uC804\uD658 \uD6C4 \uB2E4\uC2DC \uD14C\uC2A4\uD2B8\uD558\uACE0 \uD53C\uB4DC\uBC31\uC744 \uC81C\uACF5\uD574\uC57C \uD569\uB2C8\uB2E4. \uBB38\uC81C\uAC00 \uC7AC\uC2DC\uC791, \uB300\uAE30, \uD2B9\uC815 \uD30C\uC77C \uB610\uB294 \uD2B9\uC815 \uC791\uC5C5\uC744 \uD544\uC694\uB85C \uD55C\uB2E4\uBA74 \uBAA8\uB4E0 \uB2E8\uACC4\uC5D0\uC11C \uAC19\uC740 \uD14C\uC2A4\uD2B8 \uC870\uAC74\uC744 \uC720\uC9C0\uD558\uC138\uC694.",
  \u6392\u67E5_\u53EF\u4FE1\u5EA6_\u6807\u7B7E: "\uBCF4\uC7A5",
