  \u6392\u67E5_\u6D41\u7A0B_\u5B9A\u4F4D: "\uD6C4\uBCF4 \uC774\uBD84 \uD0D0\uC0C9",
  \u6392\u67E5_\u6D41\u7A0B_\u9A8C\u8BC1: "\uD50C\uB7EC\uADF8\uC778 \uB610\uB294 \uC30D \uAC80\uC99D",
